        GREEN=""
        YELLOW=""
        BLUE=""
        MAGENTA=""
        CYAN=""
        WHITE=""
        BOLD=""
        OFF=""
        result_color_table=( "" "" "" "" "" "" "" )
    ;;
    createAccountGroup)
    operation="createAccountGroup"
    ;;
    deleteAccountGroup)
    operation="deleteAccountGroup"
